#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    int n, k;    cin >> n >> k;    vll a(n);    for (int i = 0; i < n; i++) {        cin >> a[i];    }    sort(a.begin(), a.end());    int longest_length =1;    int max_length=1;    for(int i=1;i<n;i++){        if(a[i]-a[i-1]<=k){            longest_length++;                    }        else{            longest_length=1;        }        max_length = max(max_length, longest_length);    }    cout<<n-max_length<<endl;         } // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}